text:
{
  "formal_minutes": {
    "decisions": [
      "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
      "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
      "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
    ],
    "non_decisions": {
      "rejected_proposals": [
        "packageName 불일치를 무시하도록 smoke-theme-pack.mjs를 변경하자는 제안은 거절되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 확정 일정이 아니라 내부 stretch goal이다."
      ],
      "unassigned_or_tentative_items": [
        "README 설치 단계는 가능하면 목요일까지 검토하자는 의견이 있었지만, 담당자는 지정되지 않았다."
      ]
    },
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시 확인됨"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시 확인됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "정확한 마감 없음",
      "status": "확정, Minjun 결과 공유 이후 진행",
      "source_certainty": "담당자와 조건은 명시 확인됨, 마감은 미정"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토",
      "due": "목요일까지 가능하면",
      "status": "미확정, 담당자 없음",
      "source_certainty": "제안성 발언만 확인됨"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과를 확인한다.",
      "Doyun의 금요일 12:00 KST failure triage note 작성 여부를 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 확인을 추적한다.",
      "README 설치 단계 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항은 언급되지 않았으므로 추가하지 않는다.",
    "README 설치 단계 검토에는 담당자가 지정되지 않았으므로 담당자를 추정하지 않는다.",
    "Hara의 tarball 경로 확인에는 정확한 마감이 없으므로 임의 기한을 만들지 않는다.",
    "수요일 릴리스는 확정 결정이 아니라 내부 stretch goal로만 기록한다."
  ]
}
